import hashlib, time

cache = {}
COST_PER_1K = 0.002

def key(text, model):
    return hashlib.sha256(f"{model}|{text}".encode()).hexdigest()[:12]

def infer(text, model="demo", timeout_s=1.0, fail=False):
    k = key(text, model)
    if k in cache:
        return cache[k] | {"cached": True}
    if fail:
        raise TimeoutError("endpoint")
